--
-- Name: chat_event_create_match(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.chat_event_create_match() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_team_id INTEGER;
    v_new_match_id INTEGER;
BEGIN
    -- Skip if event already linked to a match
    IF NEW.match_id IS NOT NULL THEN
        RETURN NULL;
    END IF;

    SELECT team_id INTO v_team_id FROM chats WHERE id = NEW.chat_id;

    -- Only auto-create for chats backed by a team (training/pickup/team)
    IF v_team_id IS NULL THEN
        RETURN NULL;
    END IF;

        match_type_id, home_team_id, away_team_id,
        match_date, match_time, title, description,
        source_system_id, external_id
    ) VALUES (
        3,
        v_team_id,
        NULL,
        COALESCE(NEW.event_date, (NEW.start_at AT TIME ZONE 'America/New_York')::date, CURRENT_DATE),
        COALESCE(NEW.event_time, (NEW.start_at AT TIME ZONE 'America/New_York')::time),
        NEW.title,
        NEW.description,
        5,
        'chat_event:' || NEW.id::text
    )
    ON CONFLICT (source_system_id, external_id) DO UPDATE
        SET title = EXCLUDED.title,
            match_date = EXCLUDED.match_date,
            match_time = EXCLUDED.match_time
    RETURNING id INTO v_new_match_id;

    -- Back-link chat_event → match (we're AFTER INSERT now, so update directly)
    UPDATE chat_events SET match_id = v_new_match_id WHERE id = NEW.id;

    RETURN NULL;
END;
$$;


--
-- Name: FUNCTION chat_event_create_match(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.chat_event_create_match() IS 'Auto-creates a matches row (match_type=practice) for every chat_event in a chat with team_id set. AFTER INSERT so it only fires for rows actually persisted (not for rows that hit ON CONFLICT DO UPDATE).';


--
-- Name: chat_event_sync_match(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.chat_event_sync_match() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_new_date   DATE;
    v_new_time   TIME;
BEGIN
    -- No linked match yet → nothing to sync (INSERT trigger will create
    -- one if appropriate).
    IF NEW.match_id IS NULL THEN
        RETURN NULL;
    END IF;

    -- Only act if the user-visible fields actually changed.  This keeps
    -- noisy rsvp_snapshot-only updates from burning a write on matches.
    IF NEW.title           IS NOT DISTINCT FROM OLD.title
       AND NEW.event_date  IS NOT DISTINCT FROM OLD.event_date
       AND NEW.event_time  IS NOT DISTINCT FROM OLD.event_time
       AND NEW.start_at    IS NOT DISTINCT FROM OLD.start_at
    THEN
        RETURN NULL;
    END IF;

    v_new_date := COALESCE(
        NEW.event_date,
        (NEW.start_at AT TIME ZONE 'America/New_York')::date
    );
    v_new_time := COALESCE(
        NEW.event_time,
        (NEW.start_at AT TIME ZONE 'America/New_York')::time
    );

    -- Respect manual_override: skip the row silently.  Coach wins.
    UPDATE matches
       SET title      = NEW.title,
           match_date = v_new_date,
           match_time = v_new_time
     WHERE id = NEW.match_id
       AND manual_override = FALSE;

    RETURN NULL;
END;
$$;


--
-- Name: FUNCTION chat_event_sync_match(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.chat_event_sync_match() IS 'Propagates title/date/time changes from chat_events to the linked matches row. Skips rows where manual_override = TRUE so coach edits stick.';


--
-- Name: fn_auto_roster_team_chat_member(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_auto_roster_team_chat_member() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_team_id      INT;
    v_chat_type_id INT;
    v_player_id    INT;
BEGIN
    -- Nothing to do for unlinked members
    IF NEW.person_id IS NULL THEN
        RETURN NEW;
    END IF;

    SELECT c.team_id, c.chat_type_id
    INTO v_team_id, v_chat_type_id
    FROM chats c
    WHERE c.id = NEW.chat_id;

    -- Only team-bound team chats trigger auto-roster
    IF v_team_id IS NULL OR v_chat_type_id <> 1 THEN
        RETURN NEW;
    END IF;

    SELECT p.id INTO v_player_id FROM players p WHERE p.person_id = NEW.person_id;
    IF v_player_id IS NULL THEN
        -- Person exists but has no player record yet — skip silently. Player
        -- creation lives in the player-management flow, not here.
        RETURN NEW;
    END IF;

    -- Insert a roster row only if no row exists at all for (team, player).
    -- This preserves manual removals (left_at IS NOT NULL).
    SELECT v_team_id, v_player_id, CURRENT_TIMESTAMP, NULL
    WHERE NOT EXISTS (
        SELECT 1 FROM rosters r
        WHERE r.team_id = v_team_id AND r.player_id = v_player_id
    );

    RETURN NEW;
END;
$$;


--
-- Name: fn_lineups_teams_for_chat_event(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_lineups_teams_for_chat_event(p_chat_event_id integer) RETURNS text
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_chat_name text;
  v_team_id   int;
BEGIN
  SELECT c.name, c.team_id
    INTO v_chat_name, v_team_id
    FROM chat_events ce
    JOIN chats c ON c.id = ce.chat_id
   WHERE ce.id = p_chat_event_id;

  IF v_chat_name IN ('Training Lighthouse', 'Philadelphia Pickup') THEN
    RETURN '"all"';
  END IF;
  IF v_team_id IS NOT NULL THEN
    RETURN '[' || v_team_id || ']';
  END IF;
  RETURN '"all"';
END
$$;


--
-- Name: fn_lineups_teams_for_match(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_lineups_teams_for_match(p_match_id integer) RETURNS text
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_home int;
  v_away int;
  v_ids  int[];
BEGIN
  SELECT home_team_id, away_team_id
    INTO v_home, v_away
    FROM matches WHERE id = p_match_id;
  v_ids := ARRAY[]::int[];
  IF v_home IS NOT NULL THEN v_ids := array_append(v_ids, v_home); END IF;
  IF v_away IS NOT NULL THEN v_ids := array_append(v_ids, v_away); END IF;
  IF array_length(v_ids, 1) IS NULL THEN RETURN '"all"'; END IF;
  RETURN to_jsonb(v_ids)::text;
END
$$;


--
-- Name: fn_mirror_chat_event_rsvp_to_event_rsvp(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_mirror_chat_event_rsvp_to_event_rsvp() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.person_id IS NULL THEN RETURN NEW; END IF;

                           response_note, source_id, recorded_at, updated_at)
  VALUES (
    NEW.chat_event_id,
    NEW.person_id,
    COALESCE(NEW.override_rsvp_status_id, NEW.rsvp_status_id),
    COALESCE(NEW.override_note,           NEW.response_note),
    CASE WHEN NEW.override_rsvp_status_id IS NOT NULL THEN 3 ELSE 2 END,
    COALESCE(NEW.overridden_at, NEW.responded_at, NOW()),
    COALESCE(NEW.overridden_at, NEW.responded_at, NOW())
  )
  ON CONFLICT (chat_event_id, person_id) DO UPDATE SET
    rsvp_status_id = EXCLUDED.rsvp_status_id,
    response_note  = EXCLUDED.response_note,
    source_id      = EXCLUDED.source_id,
    updated_at     = EXCLUDED.updated_at;

  RETURN NEW;
END
$$;


--
-- Name: fn_notify_lineup_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_notify_lineup_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_row             record;
  v_kind            text;
  v_team_ids_json   text;
  v_payload         text;
BEGIN
  -- Use NEW for INSERT/UPDATE, OLD for DELETE.
  IF TG_OP = 'DELETE' THEN v_row := OLD; ELSE v_row := NEW; END IF;

  IF TG_TABLE_NAME = 'event_rsvps' OR TG_TABLE_NAME = 'chat_event_rsvps' THEN
    v_kind := 'rsvp';
    v_team_ids_json := fn_lineups_teams_for_chat_event(v_row.chat_event_id);

  ELSIF TG_TABLE_NAME = 'player_rsvp_history' THEN
    v_kind := 'rsvp';
    v_team_ids_json := fn_lineups_teams_for_match(v_row.event_id);

  ELSIF TG_TABLE_NAME = 'match_lineups' THEN
    v_kind := 'lineup';
    v_team_ids_json := fn_lineups_teams_for_match(v_row.match_id);

  ELSIF TG_TABLE_NAME = 'rosters' THEN
    -- Roster changes affect the R badge across multiple teams (the C++
    -- query hardcodes membership lookups against 'Lighthouse 1893 SC',
    -- 'Lighthouse Boys Club', 'Lighthouse Old Timers').  Cheapest +
    -- safest is to refresh everything visible.
    v_kind := 'roster';
    v_team_ids_json := '"all"';

  ELSIF TG_TABLE_NAME = 'team_coaches' THEN
    v_kind := 'coach';
    v_team_ids_json := '[' || COALESCE(v_row.team_id::text, '0') || ']';

  ELSIF TG_TABLE_NAME = 'chat_external_members' THEN
    -- Linking/unlinking a GM external user → person → may flip the
    -- gmOnly bucket on any team whose chat contains that external user.
    DECLARE
      v_team_id int;
    BEGIN
      SELECT team_id INTO v_team_id FROM chats WHERE id = v_row.chat_id;
      IF v_team_id IS NOT NULL THEN
        v_team_ids_json := '[' || v_team_id || ']';
      ELSE
        v_team_ids_json := '"all"';
      END IF;
    END;
    v_kind := 'chat_member';

  ELSE
    -- Unknown table — emit conservative refresh-all.
    v_kind := 'unknown';
    v_team_ids_json := '"all"';
  END IF;

  v_payload := '{"kind":"' || v_kind || '","affected_team_ids":' || v_team_ids_json || '}';

  -- pg_notify is async + nonblocking; payload max 8000 bytes.  Wrapping
  -- in PERFORM keeps the trigger return semantics clean.
  PERFORM pg_notify('fh_lineups', v_payload);

  IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
  RETURN NEW;
END
$$;


--
-- Name: fn_pool_team_membership_on_fh_register(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pool_team_membership_on_fh_register() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_player_id INT;
  v_team_id   INT;
BEGIN
  -- Only fire when transitioning from "not registered" -> "registered".
  IF NEW.fh_member_at IS NULL THEN RETURN NEW; END IF;
  IF TG_OP = 'UPDATE' AND OLD.fh_member_at IS NOT NULL THEN RETURN NEW; END IF;

  SELECT id INTO v_player_id FROM players WHERE person_id = NEW.id LIMIT 1;
  IF v_player_id IS NULL THEN
  END IF;

  FOR v_team_id IN SELECT id FROM teams WHERE is_pool LOOP
    IF NOT EXISTS (
      SELECT 1 FROM rosters
       WHERE player_id = v_player_id
         AND team_id   = v_team_id
         AND left_at IS NULL
    ) THEN
      VALUES (v_player_id, v_team_id, NOW());
    END IF;
  END LOOP;

  RETURN NEW;
END $$;


--
-- Name: fn_pool_team_membership_on_mens_assign(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pool_team_membership_on_mens_assign() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_person_id INT;
  v_player_id INT;
  v_team_id   INT;
BEGIN
  -- LA user id -> person via external_person_aliases.
  SELECT person_id INTO v_person_id
    FROM external_person_aliases
   WHERE provider = 'leagueapps'
     AND external_user_id = NEW.leagueapps_user_id::text
   LIMIT 1;
  IF v_person_id IS NULL THEN RETURN NEW; END IF;

  -- Ensure a player row exists for this person.
  SELECT id INTO v_player_id FROM players WHERE person_id = v_person_id LIMIT 1;
  IF v_player_id IS NULL THEN
    VALUES (v_person_id, 1)
    RETURNING id INTO v_player_id;
  END IF;

  -- Insert into every pool team's roster (current open membership only).
  FOR v_team_id IN SELECT id FROM teams WHERE is_pool LOOP
    IF NOT EXISTS (
      SELECT 1 FROM rosters
       WHERE player_id = v_player_id
         AND team_id   = v_team_id
         AND left_at IS NULL
    ) THEN
      VALUES (v_player_id, v_team_id, NOW());
    END IF;
  END LOOP;

  RETURN NEW;
END $$;


--
-- Name: generate_recurring_chat_events(date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_recurring_chat_events(from_date date DEFAULT (CURRENT_DATE - '90 days'::interval), up_to_date date DEFAULT (CURRENT_DATE + '90 days'::interval)) RETURNS TABLE(inserted_id integer, out_chat_id integer, out_title text, out_event_date date)
    LANGUAGE plpgsql
    AS $$
DECLARE
    sched    RECORD;
    d        DATE;
    ev_date  DATE;
    start_ts TIMESTAMPTZ;
    end_ts   TIMESTAMPTZ;
    new_id   INT;
BEGIN
    FOR sched IN
        SELECT * FROM chat_recurring_schedules WHERE is_active = true
        ORDER BY chat_id, day_of_week
    LOOP
        -- Advance from_date to the first occurrence of this weekday
        d := from_date;
        WHILE EXTRACT(DOW FROM d)::SMALLINT != sched.day_of_week LOOP
            d := d + 1;
        END LOOP;

        -- Walk forward in weekly steps
        WHILE d <= up_to_date LOOP
            ev_date  := d;
            start_ts := (ev_date::TEXT || ' ' || sched.start_time::TEXT || '+00')::TIMESTAMPTZ;
            end_ts   := ((ev_date + CASE WHEN sched.end_is_next_day THEN 1 ELSE 0 END)::TEXT
                         || ' ' || sched.end_time::TEXT || '+00')::TIMESTAMPTZ;

            -- Idempotent: skip if an event already exists for this chat + date
            IF NOT EXISTS (
                SELECT 1 FROM chat_events ce
                WHERE ce.chat_id  = sched.chat_id
                  AND ce.event_date = ev_date
            ) THEN
                RETURNING id INTO new_id;

                inserted_id   := new_id;
                out_chat_id   := sched.chat_id;
                out_title     := sched.title;
                out_event_date := ev_date;
                RETURN NEXT;
            END IF;

            d := d + 7;
        END LOOP;
    END LOOP;
END;
$$;


