);


--
-- Name: coach_rsvps_current; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.coach_rsvps_current AS
 SELECT DISTINCT ON (coach_rsvp_history.event_id, coach_rsvp_history.coach_id) coach_rsvp_history.event_id,
    coach_rsvp_history.coach_id,
    coach_rsvp_history.rsvp_status_id,
    coach_rsvp_history.notes,
    coach_rsvp_history.changed_at
   FROM public.coach_rsvp_history
  ORDER BY coach_rsvp_history.event_id, coach_rsvp_history.coach_id, coach_rsvp_history.changed_at DESC;


