    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    event_id integer NOT NULL,
    parent_id integer NOT NULL,
    rsvp_status_id integer NOT NULL,
    changed_by integer,
    change_source_id integer,
    notes text,
    changed_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL
);


--
-- Name: parent_rsvps_current; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.parent_rsvps_current AS
 SELECT DISTINCT ON (parent_rsvp_history.event_id, parent_rsvp_history.parent_id) parent_rsvp_history.event_id,
    parent_rsvp_history.parent_id,
    parent_rsvp_history.rsvp_status_id,
    parent_rsvp_history.notes,
    parent_rsvp_history.changed_at
   FROM public.parent_rsvp_history
  ORDER BY parent_rsvp_history.event_id, parent_rsvp_history.parent_id, parent_rsvp_history.changed_at DESC;


