    team_id integer NOT NULL,
    coach_id integer NOT NULL,
    coach_role_id integer,
    started_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    ended_at timestamp without time zone,
    CONSTRAINT team_coaches_check CHECK (((ended_at IS NULL) OR (ended_at > started_at)))
);


--
-- Name: TABLE team_coaches; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.team_coaches IS 'Coaches assigned to teams with temporal tracking';


--
-- Name: team_division_players; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.team_division_players AS
 SELECT rosters.id,
    rosters.team_id,
    rosters.player_id,
    rosters.jersey_number,
    (rosters.left_at IS NULL) AS is_active,
    rosters.joined_at AS created_at,
    COALESCE(rosters.left_at, rosters.joined_at) AS updated_at
   FROM public.rosters;


--
-- Name: teams; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.teams (
    id integer NOT NULL,
    division_id integer NOT NULL,
    club_id integer,
    name character varying(255) NOT NULL,
    city character varying(100),
    logo_url text,
    source_system_id integer,
    external_id character varying(100),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    slug character varying(100),
    live_match_id integer,
    live_match_pinned boolean DEFAULT false NOT NULL,
    is_pool boolean DEFAULT false NOT NULL,
    gender_category text,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: TABLE teams; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.teams IS 'Competition-specific team entries. Each team is bound to a division/season. Same club competing in multiple divisions = multiple team records with different rosters.';


--
-- Name: COLUMN teams.slug; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.teams.slug IS 'URL-safe identifier for public pinnable team links (e.g. /t/u23-men/gameday). Unique.';


--
-- Name: COLUMN teams.live_match_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.teams.live_match_id IS 'Manually pinned live match (only honored when live_match_pinned=true). Otherwise server resolves dynamically.';


--
-- Name: COLUMN teams.live_match_pinned; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.teams.live_match_pinned IS 'When true, live_match_id is sticky until coach unpins. When false, server resolves the live match dynamically (earliest non-completed, or most recent completed as fallback).';


--
-- Name: COLUMN teams.is_pool; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.teams.is_pool IS 'When true, every FH mens member is implicitly on this team''s roster (Practice/Pickup model).  When false (default), membership requires an explicit rosters row driven by mens_team_assignments.';


--
-- Name: COLUMN teams.gender_category; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.teams.gender_category IS 'Coarse gender bucket used by /api/clubs/:id team filtering: "mens" | "womens" | "youth" | NULL.  The /lineups (mens) screen filters to gender_category=mens or NULL; a future womens lineup screen will pass ?gender=womens to surface women''s teams instead.';


