\.
COPY public.schedule_preferences (id, schedule_generation_id, preference_type_id, preference_value, weight) FROM stdin;
\.
COPY public.schedule_rivalry_pairs (id, schedule_generation_id, team_id_1, team_id_2, games_count) FROM stdin;
\.
COPY public.schedule_statuses (id, name, description, is_terminal, sort_order) FROM stdin;
